import type { ScaleThreshold, ScaleQuantize } from 'd3-scale';

import { buildColorRule } from './build-color-rule.js';
import type { ColorRuleProps } from '../../core/types/color-rule.js';
import { getTokenComputedStyle } from '../../core/utils/getTokenComputedStyle.js';
import { OUT_OF_RANGE_NODE_COLOR } from '../constants.js';
import type { InternalTreeMapNode } from '../types/internal.js';

const getColoredLeafNodes = (
  nodes: InternalTreeMapNode[],
  scale: ScaleQuantize<string, never> | ScaleThreshold<number, string>,
  min: number,
  max: number,
  colorRules: ColorRuleProps[],
) =>
  nodes.map((node) => {
    const ruleColor = buildColorRule(node, colorRules, 'value');
    return {
      ...node,
      color: { Default: ruleColor ?? getNodeColor(node, scale, min, max) },
    };
  });

const getNodeColor = (
  node: InternalTreeMapNode,
  scale: ScaleQuantize<string, never> | ScaleThreshold<number, string>,
  min: number,
  max: number,
) => {
  if (node.value >= min && node.value <= max) {
    return getTokenComputedStyle(scale(node.value));
  }

  return OUT_OF_RANGE_NODE_COLOR;
};

/**
 * Function to apply colorPalette to the tree
 * @param rootNode - InternalTreeMapNode
 * @param scale -
 * @param min -
 * @param max -
 * @param colorRules -
 * @returns - children array with applied colors
 */
export const getRangeColoredNodes = (
  rootNode: InternalTreeMapNode,
  scale: ScaleQuantize<string, never> | ScaleThreshold<number, string>,
  min: number,
  max: number,
  colorRules: ColorRuleProps[],
) =>
  rootNode.children?.map((clusterNode) => ({
    ...clusterNode,
    children: getColoredLeafNodes(
      clusterNode.children || [],
      scale,
      min,
      max,
      colorRules,
    ),
  }));
